css:
.loader { --size: var(--loader-size); --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); width: var(--size); height: var(--size); position: relative; display: grid; place-items: center; isolation: isolate; }
.core { width: 38%; height: 38%; border-radius: 50%; background: radial-gradient(circle at 35% 25%, #ffffff 0 7%, var(--accent) 18%, var(--accent-2) 58%, #070816 100%); box-shadow: 0 0 calc(var(--size) * .25) color-mix(in srgb, var(--accent) 70%, transparent), inset 0 0 calc(var(--size) * .12) #fff8; animation: nebula-core calc(var(--speed) * 2.2) ease-in-out infinite; }
.ribbon { position: absolute; width: 84%; height: 34%; border-radius: 999px; border: calc(var(--size) * .035) solid transparent; border-top-color: var(--accent); border-bottom-color: color-mix(in srgb, var(--accent-2) 80%, transparent); filter: drop-shadow(0 0 10px var(--accent)); transform: rotateX(66deg); animation: nebula-spin calc(var(--speed) * 1.7) linear infinite; }
.ribbon-b { width: 76%; height: 48%; transform: rotateX(66deg) rotateZ(70deg); animation-duration: calc(var(--speed) * 2.3); animation-direction: reverse; opacity: .75; }
.spark { position: absolute; width: 9%; height: 9%; border-radius: 50%; background: #fff; box-shadow: 0 0 14px 3px var(--accent-2); transform-origin: 0 calc(var(--size) * .34); animation: nebula-spark calc(var(--speed) * 1.7) linear infinite; }
.spark-a { top: 17%; left: 50%; }
.spark-b { top: 49%; left: 82%; animation-delay: calc(var(--speed) * -.85); }
@keyframes nebula-spin { to { rotate: 360deg; } }
@keyframes nebula-spark { to { transform: rotate(360deg); } }
@keyframes nebula-core { 0%,100% { transform: scale(.88); } 50% { transform: scale(1.08); } }
